import axios from "axios";

// Use environment variable or fallback
const API_URL = process.env.REACT_APP_API_URL || "http://localhost:8080/api";

const api = axios.create({
  baseURL: API_URL,
  headers: {
    "Content-Type": "application/json",
  },
});

// Axios interceptor to add JWT token (if exists)
api.interceptors.request.use((config) => {
  const token =
    localStorage.getItem("nfxtoken") || sessionStorage.getItem("nfxtoken");
  if (token) {
    config.headers.Authorization = `Bearer ${token}`;
  }
  return config;
});

// ✅ Signup
export const signup = async (email, password) => {
  return api.post("/auth/signup", { email, password });
};

// ✅ Login
export const login = async (email, password) => {
  const response = await api.post("/auth/login", { email, password });
  return response.data; // return only the token
};

// ✅ Example protected call
export const getProtectedData = async () => {
  return api.get("/protected");
};

// ✅ Export both named + default (so old imports still work)
export default api;
